# Custom decorator for caching expensive database queries
def cache(expire_time=300):
    def decorator(f):
        @functools.wraps(f)
        def wrapper(*args, **kwargs):
            key = f.__name__ + '_' + '_'.join(map(str, args)) + '_'.join(map(str, kwargs))
            cached_value = redis_client.get(key)
            if cached_value:
                return cached_value.decode('utf-8')
            else:
                result = f(*args, **kwargs)
                redis_client.setex(key, expire_time, result)
                return result
        return wrapper
    return decorator

